from __future__ import annotations
from dataclasses import dataclass, field
from typing import Any
import json


@dataclass
class KGNode:
    id: str                         # canonical id, e.g. "alice"
    label: str                      # human-readable name
    node_type: str                  # "Person", "Project", "Org", ...
    attrs: dict[str, Any] = field(default_factory=dict)

    def to_text(self) -> str:
        parts = [f"{self.label} ({self.node_type})"]
        for k, v in self.attrs.items():
            parts.append(f"  {k}: {v}")
        return "\n".join(parts)


@dataclass
class KGEdge:
    src: str                        # source node id
    rel: str                        # relation label, e.g. "MEMBER_OF"
    dst: str                        # destination node id
    attrs: dict[str, Any] = field(default_factory=dict)

    def to_text(self) -> str:
        return f"{self.src} --[{self.rel}]--> {self.dst}"

import sqlite3

DDL = """
CREATE TABLE IF NOT EXISTS kg_nodes (
    id        TEXT PRIMARY KEY,
    label     TEXT NOT NULL,
    node_type TEXT NOT NULL,
    attrs     TEXT NOT NULL DEFAULT '{}'
);
CREATE TABLE IF NOT EXISTS kg_edges (
    id   INTEGER PRIMARY KEY AUTOINCREMENT,
    src  TEXT NOT NULL,
    rel  TEXT NOT NULL,
    dst  TEXT NOT NULL,
    attrs TEXT NOT NULL DEFAULT '{}',
    UNIQUE (src, rel, dst)
);
CREATE INDEX IF NOT EXISTS idx_edges_src ON kg_edges(src);
CREATE INDEX IF NOT EXISTS idx_edges_dst ON kg_edges(dst);
CREATE INDEX IF NOT EXISTS idx_edges_rel ON kg_edges(rel);
"""


class KnowledgeGraph:
    def __init__(self, db_path: str = ":memory:"):
        self.con = sqlite3.connect(db_path)
        self.con.executescript(DDL)
        self.con.commit()

    # ── write ────────────────────────────────────────────────────────────
    def upsert_node(self, node: KGNode) -> None:
        self.con.execute(
            """INSERT INTO kg_nodes(id, label, node_type, attrs)
               VALUES (?,?,?,?)
               ON CONFLICT(id) DO UPDATE SET
                 label=excluded.label,
                 node_type=excluded.node_type,
                 attrs=json_patch(attrs, excluded.attrs)""",
            (node.id, node.label, node.node_type, json.dumps(node.attrs)),
        )
        self.con.commit()

    def upsert_edge(self, edge: KGEdge) -> None:
        self.con.execute(
            """INSERT INTO kg_edges(src, rel, dst, attrs)
               VALUES (?,?,?,?)
               ON CONFLICT(src, rel, dst) DO UPDATE SET
                 attrs=json_patch(attrs, excluded.attrs)""",
            (edge.src, edge.rel, edge.dst, json.dumps(edge.attrs)),
        )
        self.con.commit()

    # ── read ─────────────────────────────────────────────────────────────
    def get_node(self, node_id: str) -> KGNode | None:
        row = self.con.execute(
            "SELECT id, label, node_type, attrs FROM kg_nodes WHERE id=?",
            (node_id,)
        ).fetchone()
        if row is None:
            return None
        return KGNode(row[0], row[1], row[2], json.loads(row[3]))

    def neighbors(self, node_id: str, rel: str | None = None) -> list[KGEdge]:
        if rel:
            rows = self.con.execute(
                "SELECT src, rel, dst, attrs FROM kg_edges WHERE src=? AND rel=?",
                (node_id, rel)
            ).fetchall()
        else:
            rows = self.con.execute(
                "SELECT src, rel, dst, attrs FROM kg_edges WHERE src=?",
                (node_id,)
            ).fetchall()
        return [KGEdge(r[0], r[1], r[2], json.loads(r[3])) for r in rows]

from collections import deque


def bfs_subgraph(
    kg: KnowledgeGraph,
    start_id: str,
    max_hops: int = 2,
    rel_filter: set[str] | None = None,
) -> list[KGEdge]:
    """Return all edges reachable from start_id within max_hops."""
    visited: set[str] = {start_id}
    queue: deque[tuple[str, int]] = deque([(start_id, 0)])
    result: list[KGEdge] = []

    while queue:
        node_id, depth = queue.popleft()
        if depth >= max_hops:
            continue
        for edge in kg.neighbors(node_id):
            if rel_filter and edge.rel not in rel_filter:
                continue
            result.append(edge)
            if edge.dst not in visited:
                visited.add(edge.dst)
                queue.append((edge.dst, depth + 1))

    return result


def subgraph_to_text(kg: KnowledgeGraph, edges: list[KGEdge]) -> str:
    lines: list[str] = []
    seen_nodes: set[str] = set()
    for e in edges:
        for nid in (e.src, e.dst):
            if nid not in seen_nodes:
                node = kg.get_node(nid)
                if node:
                    lines.append(node.to_text())
                    seen_nodes.add(nid)
        lines.append(f"  -> {e.to_text()}")
    return "\n".join(lines)

import anthropic

_CLIENT = anthropic.Anthropic()
_EXTRACT_PROMPT = """
Read the text below and extract knowledge graph facts.
Return JSON: {"nodes": [{"id", "label", "node_type", "attrs"}], "edges": [{"src", "rel", "dst"}]}

Rules:
- node ids: lowercase, no spaces ("alice", "acme_corp")
- node_type: one of Person, Project, Organisation, Feature, Tool, Concept
- rel: SCREAMING_SNAKE_CASE (WORKS_FOR, MEMBER_OF, HAS_FEATURE, USES, REPORTS_TO, OWNS)
- Only include facts that are explicitly stated.

Text:
<text>{text}</text>
"""


def extract_graph_facts(text: str) -> tuple[list[KGNode], list[KGEdge]]:
    resp = _CLIENT.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=800,
        messages=[{"role": "user", "content": _EXTRACT_PROMPT.format(text=text)}],
    )
    try:
        raw = json.loads(resp.content[0].text)
    except (json.JSONDecodeError, IndexError):
        return [], []

    nodes = [
        KGNode(n["id"], n["label"], n["node_type"], n.get("attrs", {}))
        for n in raw.get("nodes", [])
    ]
    edges = [
        KGEdge(e["src"], e["rel"], e["dst"])
        for e in raw.get("edges", [])
    ]
    return nodes, edges


def ingest_turn(kg: KnowledgeGraph, text: str) -> None:
    nodes, edges = extract_graph_facts(text)
    for node in nodes:
        kg.upsert_node(node)
    for edge in edges:
        kg.upsert_edge(edge)

QUERY_GRAPH_TOOL = {
    "name": "query_graph",
    "description": "Query the knowledge graph. Returns edges matching the pattern.",
    "input_schema": {
        "type": "object",
        "properties": {
            "src":  {"type": "string", "description": "Source node id (optional)"},
            "rel":  {"type": "string", "description": "Relationship type (optional)"},
            "dst":  {"type": "string", "description": "Destination node id (optional)"},
            "hops": {"type": "integer", "description": "Max BFS depth from src (default 1)"},
        },
        "required": [],
    },
}


def handle_query_graph(
    kg: KnowledgeGraph, inp: dict
) -> str:
    src  = inp.get("src")
    rel  = inp.get("rel")
    dst  = inp.get("dst")
    hops = inp.get("hops", 1)

    if src and hops > 1:
        edges = bfs_subgraph(kg, src, max_hops=hops, rel_filter={rel} if rel else None)
    else:
        clauses, params = [], []
        if src:
            clauses.append("src=?"); params.append(src)
        if rel:
            clauses.append("rel=?"); params.append(rel)
        if dst:
            clauses.append("dst=?"); params.append(dst)
        where = ("WHERE " + " AND ".join(clauses)) if clauses else ""
        rows = kg.con.execute(
            f"SELECT src, rel, dst, attrs FROM kg_edges {where}", params
        ).fetchall()
        edges = [KGEdge(r[0], r[1], r[2], json.loads(r[3])) for r in rows]

    if not edges:
        return "No edges found matching the query."
    return subgraph_to_text(kg, edges)

# Assumes EntityRegistry from the Entity Tracking sub-subtopic
def sync_registry_to_graph(
    registry,   # EntityRegistry
    kg: KnowledgeGraph,
) -> None:
    for entity in registry.all_entities():
        node = KGNode(
            id=entity.canonical_id,
            label=entity.name,
            node_type=entity.entity_type,
            attrs=entity.attributes,
        )
        kg.upsert_node(node)
